/**
 * @summary Get all contracts (admin)
 */
export const getGetAdminContractsUrl = () => {
  return `/api/admin/contracts`;
};

export const getAdminContracts = async (
  options?: RequestInit,
): Promise<ContractListResponse> => {
  return customFetch<ContractListResponse>(getGetAdminContractsUrl(), {
    ...options,
    method: "GET",
  });
};

export const getGetAdminContractsQueryKey = () => {
  return [`/api/admin/contracts`] as const;
};

export const getGetAdminContractsQueryOptions = <
  TData = Awaited<ReturnType<typeof getAdminContracts>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getAdminContracts>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetAdminContractsQueryKey();

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getAdminContracts>>
  > = ({ signal }) => getAdminContracts({ signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getAdminContracts>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetAdminContractsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAdminContracts>>
>;
export type GetAdminContractsQueryError = ErrorType<unknown>;

/**
 * @summary Get all contracts (admin)
 */

export function useGetAdminContracts<
  TData = Awaited<ReturnType<typeof getAdminContracts>>,
  TError = ErrorType<unknown>,
>(options?: {
  query?: UseQueryOptions<
    Awaited<ReturnType<typeof getAdminContracts>>,
    TError,
    TData
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetAdminContractsQueryOptions(options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
